import React, { useState } from 'react';
import { useAppDispatch } from '../../store/hooks';
import { Button, dispatchAppToast } from '@linm-soft/common-components';
import styles from '../../styles/erpPage.module.css';
import {
  SharedCatalogProposalModal,
  type SharedCatalogProposalMode,
  type SharedCatalogProposalSubmitChange,
} from './SharedCatalogProposalModal';
import type { SharedCatalogProposalFieldDef } from './sharedCatalogProposalFieldRegistry';

export interface SharedCatalogProposalTriggerProps {
  testIdPrefix: string;
  catalogKind: string;
  label?: string;
  variant?: 'primary' | 'secondary';
  size?: 'sm' | 'md';
  iconClass?: string;
  modes: SharedCatalogProposalMode[];
  context: 'catalog' | 'item';
  entityKey?: string;
  entityLabel?: string;
  defaultChangeAction?: 'Update' | 'Delete' | 'Create';
  currentValues?: Record<string, unknown>;
  disabled?: boolean;
  /** Icon-only row action (no Button wrapper). */
  iconOnly?: boolean;
  onSubmitUsage: (note?: string) => Promise<void>;
  onSubmitChange: (payload: SharedCatalogProposalSubmitChange) => Promise<void>;
  /** When set, wraps change submit with entity key (catalog toolbar). */
  onSubmitChangeForEntity?: (
    entityKey: string,
    payload: SharedCatalogProposalSubmitChange,
  ) => Promise<void>;
  proposalFieldDefs?: SharedCatalogProposalFieldDef[];
}

/** Nút «Đề xuất» + modal 2 mode — SSOT shared catalog proposal UX. */
export const SharedCatalogProposalTrigger: React.FC<SharedCatalogProposalTriggerProps> = ({
  testIdPrefix,
  catalogKind,
  label = 'Đề xuất',
  variant = 'secondary',
  size = 'sm',
  iconClass = 'fas fa-paper-plane',
  modes,
  context,
  entityKey,
  entityLabel,
  defaultChangeAction,
  currentValues,
  disabled,
  iconOnly,
  onSubmitUsage,
  onSubmitChange,
  onSubmitChangeForEntity,
  proposalFieldDefs,
}) => {
  const dispatch = useAppDispatch();
  const [open, setOpen] = useState(false);

  const openModal = () => {
    if (disabled) return;
    if (!entityKey && modes.includes('change')) {
      dispatchAppToast(dispatch, { message: 'Chọn một dòng trong danh sách trước khi đề xuất', type: 'error' });
      return;
    }
    setOpen(true);
  };

  return (
    <>
      {iconOnly ? (
        <button
          type="button"
          className={styles.actionBtn}
          title="Đề xuất"
          disabled={disabled}
          data-testid={`${testIdPrefix}-propose-btn`}
          onClick={openModal}
        >
          <i className={iconClass || 'fas fa-paper-plane'} />
        </button>
      ) : (
        <Button
          variant={variant}
          size={size}
          disabled={disabled}
          data-testid={`${testIdPrefix}-propose-btn`}
          onClick={openModal}
        >
          {iconClass ? <i className={iconClass} /> : null} {label}
        </Button>
      )}
      <SharedCatalogProposalModal
        testIdPrefix={testIdPrefix}
        isOpen={open}
        onClose={() => setOpen(false)}
        catalogKind={catalogKind}
        modes={modes}
        context={context}
        entityKey={entityKey}
        entityLabel={entityLabel}
        defaultChangeAction={defaultChangeAction}
        currentValues={currentValues}
        onSubmitUsage={onSubmitUsage}
        onSubmitChange={onSubmitChange}
        onSubmitChangeWithKey={onSubmitChangeForEntity}
        proposalFieldDefs={proposalFieldDefs}
      />
    </>
  );
};
