import { createDocumentHistoryClient } from '@linm-soft/common-components';

export const erpDocumentHistoryClient = createDocumentHistoryClient({
  basePath: '/document-history',
  pageSize: 20,
});

export const hrCatalogDocumentTypes = {
  'hr-employees': 'HrEmployee',
  'hr-work-shifts': 'HrWorkShift',
  'hr-employee-groups': 'HrEmployeeGroup',
} as const;

export type HrCatalogDocumentKind = keyof typeof hrCatalogDocumentTypes;

export function hrCatalogDocumentType(catalogKind: string): string | undefined {
  return hrCatalogDocumentTypes[catalogKind as HrCatalogDocumentKind];
}
