import { useCallback, useEffect, useState } from 'react';
import { catalogUiSchemaService } from '../../../services/catalog/catalogUiSchemaService';
import type { CatalogUiSchema } from '../../../types/catalogUiSchema';

export function useCatalogUiSchema(catalogKind: string, configMode = false): {
  schema: CatalogUiSchema | null;
  loading: boolean;
  error: string | null;
  reload: () => void;
} {
  const [schema, setSchema] = useState<CatalogUiSchema | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [reloadKey, setReloadKey] = useState(0);

  const reload = useCallback(() => setReloadKey(k => k + 1), []);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setError(null);
    const t = setTimeout(() => {
      catalogUiSchemaService
        .get(catalogKind, configMode)
        .then(data => {
          if (!cancelled) setSchema(data);
        })
        .catch(err => {
          if (!cancelled) {
            setError(err instanceof Error ? err.message : 'Lỗi tải cấu hình danh mục');
            setSchema(null);
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [catalogKind, configMode, reloadKey]);

  return { schema, loading, error, reload };
}
